INSERT INTO public.lyrics (user_id, title, content, status, mood, tags, notes) VALUES ('361c3e2f-90a0-4ea4-8ce2-66690135cc2f', 'Drawing Board (Jack Daniels rewrite WIP)', E'[Verse 1]\nI took the feller ''round back to the drawing board;\nWe get to sketchin'' and editing audio\nI fill your 5 gallon bucket with sumptuous particles\nI got a country void in my hand.', 'in-progress', 'gritty', ARRAY['rewrite','lil-darkie','wip','country'], E'Rewrite of lil Darkie - Jack Daniels.\n\nOriginal verse 1 for reference:\nI took that fella round back to the water hole / I turn that critter to dust and it''s audible / I turn your 10-gallon hat to some particles / Can''t even read what they wrote in my articles / I''m so illiterate, I can''t even read a little bit / I keep a banjo my hip and I diddle it / Middle kid, I got some siblings / Rat eat the scrap on the floor and the niblings / I keep a bat I keep score in my backyard / My daddy fat and he poor it ain''t that hard / My dad republican but he live on unemployment / Farming don''t bring no enjoyment / Kids in my town is afflicted with opiates / Heroin needles, addiction is copious / Never appropriate, uncle yelling ''bout the Soviets / Taking over his associates');